import theme from 'theme'

const styles = {
  box: {
    widht: '100%',
    padding: theme.spacing(2),
    marginBottom: theme.spacing(0.5),
    border: '1px solid transparent',
    backgroundColor: '#fcf8e3',
    borderColor: '#faebcc'
  },
  link: {
    color: '#0532ff !important'
  }
}

export default styles
